from __future__ import annotations
import re
import unicodedata
from typing import Any
from urllib.parse import urlencode
import httpx
from langflow.custom import Component
from langflow.io import BoolInput, DropdownInput, IntInput, MessageTextInput, Output
from langflow.schema import Data



class RillFilterValuesTool(Component):
    display_name = "Rill Filter Values"
    description = (
        "Lists valid Rill filter values for brand, country, media, status, "
        "or workflow_process. Use this when the user asks available values "
        "or when validation needs examples after a failed resolution."
    )
    documentation: str = "https://docs.langflow.org/components-custom-components"
    icon = "ListFilter"
    name = "RillFilterValuesTool"

    DEFAULT_API_BASE = "http://rillcontacts-rill.n8n.svc.cluster.local:9009/v1/instances/default/api"

    DIMENSION_TO_ENDPOINT = {
        "brand": "filter_brands",
        "country": "filter_countries",
        "media": "filter_media",
        "status": "filter_statuses",
        "workflow_process": "filter_workflows",
    }

    DIMENSION_ALIASES = {
        "brand": "brand",
        "brands": "brand",
        "country": "country",
        "countries": "country",
        "media": "media",
        "medium": "media",
        "status": "status",
        "statuses": "status",
        "workflow": "workflow_process",
        "workflows": "workflow_process",
        "workflow_process": "workflow_process",
        "workflow process": "workflow_process",
        "process": "workflow_process",
    }

    VALUE_FIELD_CANDIDATES = {
        "brand": ["brand", "brand_name", "value", "label", "name"],
        "country": ["country", "country_name", "value", "label", "name"],
        "media": ["media", "media_name", "value", "label", "name"],
        "status": ["status", "value", "label", "name"],
        "workflow_process": ["workflow_process", "workflow", "process", "value", "label", "name"],
    }

    ENRICHED_FIELDS = [
        "rank",
        "value",
        "label",
        "normalized_value",
        "normalized_compact",
        "row_count",
        "total_committed_eur",
        "total_gross_investment_eur",
        "total_media_net_eur",
        "total_media_agency_fees_eur",
        "total_technical_costs_eur",
        "total_media_taxes_eur",
        "total_non_media_costs_eur",
    ]

    inputs = [
        DropdownInput(
            name="dimension",
            display_name="Dimension",
            info=(
                "Filter dimension to list. Allowed values: brand, country, "
                "media, status, workflow_process."
            ),
            options=["brand", "country", "media", "status", "workflow_process"],
            value="brand",
            tool_mode=True,
        ),
        IntInput(
            name="limit",
            display_name="Limit",
            info="Maximum number of values to return.",
            value=100,
            tool_mode=True,
        ),
        MessageTextInput(
            name="base_url",
            display_name="Rill API Base URL",
            info=(
                "Base Rill API URL without the endpoint name. Keep this hidden "
                "from the agent; only the component should build final URLs."
            ),
            value=DEFAULT_API_BASE,
            advanced=True,
        ),
        IntInput(
            name="timeout",
            display_name="Timeout Seconds",
            info="HTTP timeout in seconds.",
            value=30,
            advanced=True,
        ),
        BoolInput(
            name="include_metadata",
            display_name="Include Metadata",
            info="Return endpoint, URL, HTTP metadata, and raw payload for debugging.",
            value=False,
            advanced=True,
        ),
    ]

    outputs = [
        Output(display_name="Filter Values", name="filter_values", method="get_filter_values"),
    ]

    def _normalize_dimension(self, raw_dimension: str | None) -> str:
        dimension = (raw_dimension or "").strip().lower().replace("-", "_")
        dimension = " ".join(dimension.split())
        dimension = self.DIMENSION_ALIASES.get(dimension, dimension)

        if dimension not in self.DIMENSION_TO_ENDPOINT:
            allowed = ", ".join(self.DIMENSION_TO_ENDPOINT.keys())
            raise ValueError(f"Unsupported dimension '{raw_dimension}'. Allowed values: {allowed}.")

        return dimension

    def _safe_limit(self) -> int:
        try:
            limit = int(self.limit or 100)
        except (TypeError, ValueError):
            limit = 100

        return max(1, min(limit, 500))

    def _build_url(self, endpoint: str, limit: int) -> str:
        base_url = (self.base_url or self.DEFAULT_API_BASE).strip().rstrip("/")
        query = urlencode({"limit": limit})
        return f"{base_url}/{endpoint}?{query}"

    def _normalize_text(self, value: Any) -> str:
        text = "" if value is None else str(value)

        text = unicodedata.normalize("NFKD", text)
        text = "".join(ch for ch in text if not unicodedata.combining(ch))
        text = text.casefold()
        text = re.sub(r"[^a-z0-9]+", " ", text)
        text = re.sub(r"\s+", " ", text).strip()

        return text

    def _normalize_compact(self, value: Any) -> str:
        return re.sub(r"[^a-z0-9]+", "", self._normalize_text(value))

    def _extract_result_rows(self, payload: Any) -> list[Any]:
        if isinstance(payload, dict):
            for key in ("result", "data", "rows", "values", "items", "matches"):
                value = payload.get(key)

                if isinstance(value, list):
                    return value

                if value is not None:
                    return [value]

            return [payload]

        if isinstance(payload, list):
            return payload

        if payload is None:
            return []

        return [payload]

    def _extract_value(self, item: Any, dimension: str) -> Any:
        if not isinstance(item, dict):
            return item

        for field in self.VALUE_FIELD_CANDIDATES[dimension]:
            if field in item and item[field] not in (None, ""):
                return item[field]

        if len(item) == 1:
            return next(iter(item.values()))

        return None

    def _safe_float(self, value: Any) -> float:
        try:
            if value is None:
                return 0.0
            return float(value)
        except (TypeError, ValueError):
            return 0.0

    def _normalize_item(self, item: Any, dimension: str) -> dict[str, Any] | None:
        value = self._extract_value(item, dimension)

        if value in (None, ""):
            return None

        normalized_text = self._normalize_text(value)
        normalized_compact = self._normalize_compact(value)

        if not normalized_compact:
            return None

        normalized: dict[str, Any] = {
            "value": value,
            "label": value,
            "normalized_value": normalized_text,
            "normalized_compact": normalized_compact,
        }

        if isinstance(item, dict):
            for field in self.ENRICHED_FIELDS:
                if field in item and item[field] is not None:
                    normalized[field] = item[field]

            normalized["value"] = value
            normalized["label"] = normalized.get("label") or value
            normalized["normalized_value"] = normalized.get("normalized_value") or normalized_text
            normalized["normalized_compact"] = normalized.get("normalized_compact") or normalized_compact

            if self.include_metadata:
                normalized["raw"] = item

        elif self.include_metadata:
            normalized["raw"] = item

        return normalized

    def _normalize_items(self, rows: list[Any], dimension: str) -> list[dict[str, Any]]:
        items: list[dict[str, Any]] = []
        seen: set[str] = set()

        for row in rows:
            item = self._normalize_item(row, dimension)

            if not item:
                continue

            marker = str(item.get("normalized_compact") or "")

            if not marker:
                continue

            if marker in seen:
                continue

            seen.add(marker)
            items.append(item)

        items.sort(
            key=lambda item: (
                -self._safe_float(item.get("row_count")),
                str(item.get("value") or ""),
            )
        )

        return items

    def _error_response(self, dimension: str | None, error_type: str, message: str) -> Data:
        payload = {
            "ok": False,
            "tool": self.name,
            "dimension": dimension,
            "error_type": error_type,
            "error": message,
        }

        self.status = payload
        return Data(data=payload)

    def get_filter_values(self) -> Data:
        try:
            dimension = self._normalize_dimension(self.dimension)
        except ValueError as exc:
            return self._error_response(None, "invalid_dimension", str(exc))

        endpoint = self.DIMENSION_TO_ENDPOINT[dimension]
        limit = self._safe_limit()
        url = self._build_url(endpoint, limit)
        timeout_seconds = float(self.timeout or 30)

        try:
            with httpx.Client(timeout=timeout_seconds, follow_redirects=False) as client:
                response = client.get(url, headers={"User-Agent": "Langflow/1.0"})

            try:
                payload = response.json()
            except ValueError:
                return self._error_response(
                    dimension,
                    "invalid_json",
                    f"Rill returned non-JSON response with HTTP {response.status_code}.",
                )

            if response.status_code >= 400:
                return self._error_response(
                    dimension,
                    "http_error",
                    f"Rill returned HTTP {response.status_code}: {payload}",
                )

        except httpx.TimeoutException:
            return self._error_response(
                dimension,
                "timeout",
                f"Rill request timed out after {timeout_seconds:g}s.",
            )

        except httpx.RequestError as exc:
            return self._error_response(dimension, "request_error", str(exc))

        rows = self._extract_result_rows(payload)
        items = self._normalize_items(rows, dimension)
        values = [item["value"] for item in items]

        result: dict[str, Any] = {
            "ok": True,
            "tool": self.name,
            "dimension": dimension,
            "values": values,
            "items": items,
            "rows": items,
            "count": len(values),
            "limit": limit,
        }

        if self.include_metadata:
            result["metadata"] = {
                "endpoint": endpoint,
                "url": url,
                "http_status": response.status_code,
                "raw_payload": payload,
            }

        self.status = f"{dimension}: {len(values)} values"
        return Data(data=result)

from __future__ import annotations

import re
import unicodedata
from difflib import SequenceMatcher
from typing import Any
from urllib.parse import urlencode

import httpx

from lfx.custom.custom_component.component import Component
from lfx.io import BoolInput, DropdownInput, IntInput, MessageTextInput, Output
from lfx.schema.data import Data


class RillResolveValueTool(Component):
    display_name = "Rill Resolve Value"
    description = (
        "Validates and resolves a raw user value against Rill canonical filter values. "
        "Supports exact, prefix, contains, included and fuzzy matching. "
        "Use before budget queries when the user provides a brand, country, media, "
        "status, or workflow_process filter."
    )
    documentation: str = "https://docs.langflow.org/components-custom-components"
    icon = "SearchCheck"
    name = "RillResolveValueTool"

    DEFAULT_API_BASE = (
        "http://rillcontacts-rill.n8n.svc.cluster.local:9009"
        "/v1/instances/default/api"
    )

    DIMENSION_TO_ENDPOINT = {
        "brand": "resolve_brand",
        "country": "resolve_country",
        "media": "resolve_media",
        "status": "resolve_status",
        "workflow_process": "resolve_workflow",
    }

    DIMENSION_ALIASES = {
        "brand": "brand",
        "brands": "brand",
        "country": "country",
        "countries": "country",
        "media": "media",
        "medium": "media",
        "status": "status",
        "statuses": "status",
        "workflow": "workflow_process",
        "workflows": "workflow_process",
        "workflow_process": "workflow_process",
        "workflow process": "workflow_process",
        "process": "workflow_process",
    }

    VALUE_FIELD_CANDIDATES = {
        "brand": ["brand", "brand_name", "value", "label", "name"],
        "country": ["country", "country_name", "value", "label", "name"],
        "media": ["media", "media_name", "value", "label", "name"],
        "status": ["status", "value", "label", "name"],
        "workflow_process": [
            "workflow_process",
            "workflow",
            "process",
            "value",
            "label",
            "name",
        ],
    }

    SCORE_FIELD_CANDIDATES = [
        "score",
        "similarity_score",
        "similarity",
        "confidence",
        "rank_score",
    ]

    MATCH_RANK = {
        "exact": 1,
        "starts_with": 2,
        "contains": 3,
        "included": 4,
        "fuzzy": 5,
    }

    METRIC_TERMS_COMPACT = {
        "medianet",
        "netmedia",
        "grossinvestment",
        "investment",
        "invest",
        "mediaagencyfees",
        "agencyfees",
        "feesagency",
        "fees",
        "technicalcosts",
        "technicalcost",
        "technical",
        "mediataxes",
        "taxesmedia",
        "nonmediacosts",
        "nonmedia",
        "committed",
        "commitment",
    }

    AUTO_SELECT_MIN_SCORE = 0.88
    AUTO_SELECT_MIN_GAP = 0.04

    inputs = [
        DropdownInput(
            name="dimension",
            display_name="Dimension",
            info="Allowed values: brand, country, media, status, workflow_process.",
            options=[
                "brand",
                "country",
                "media",
                "status",
                "workflow_process",
            ],
            value="brand",
            tool_mode=True,
        ),
        MessageTextInput(
            name="q",
            display_name="Raw Value",
            info=(
                "Raw value typed by the user, for example a brand, country, "
                "media, status, or workflow_process."
            ),
            value="",
            tool_mode=True,
        ),
        IntInput(
            name="limit",
            display_name="Limit",
            info="Maximum number of candidate matches to return.",
            value=10,
            tool_mode=True,
        ),
        MessageTextInput(
            name="base_url",
            display_name="Rill API Base URL",
            info=(
                "Base Rill API URL without endpoint name. "
                "Keep advanced; do not expose raw URLs to the agent."
            ),
            value=DEFAULT_API_BASE,
            advanced=True,
        ),
        IntInput(
            name="timeout",
            display_name="Timeout Seconds",
            info="HTTP timeout in seconds.",
            value=30,
            advanced=True,
        ),
        BoolInput(
            name="include_metadata",
            display_name="Include Metadata",
            info="Return endpoint and HTTP metadata for debugging.",
            value=False,
            advanced=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Resolved Value",
            name="resolved_value",
            method="resolve_value",
        ),
    ]

    def _normalize_dimension(self, raw_dimension: str | None) -> str:
        dimension = (raw_dimension or "").strip().lower().replace("-", "_")
        dimension = " ".join(dimension.split())
        dimension = self.DIMENSION_ALIASES.get(dimension, dimension)

        if dimension not in self.DIMENSION_TO_ENDPOINT:
            allowed = ", ".join(self.DIMENSION_TO_ENDPOINT.keys())
            raise ValueError(
                f"Unsupported dimension '{raw_dimension}'. "
                f"Allowed values: {allowed}."
            )

        return dimension

    def _safe_limit(self) -> int:
        try:
            limit = int(self.limit or 10)
        except (TypeError, ValueError):
            limit = 10

        return max(1, min(limit, 50))

    def _build_url(self, endpoint: str, q: str, limit: int) -> str:
        base_url = (self.base_url or self.DEFAULT_API_BASE).strip().rstrip("/")
        query = urlencode({"q": q, "limit": limit})
        return f"{base_url}/{endpoint}?{query}"

    def _extract_rows(self, payload: Any) -> list[Any]:
        if isinstance(payload, dict):
            for key in (
                "matches",
                "results",
                "result",
                "data",
                "rows",
                "values",
            ):
                value = payload.get(key)

                if isinstance(value, list):
                    return value

                if value is not None:
                    return [value]

            return [payload]

        if isinstance(payload, list):
            return payload

        if payload is None:
            return []

        return [payload]

    def _extract_candidate_value(self, item: Any, dimension: str) -> Any:
        if not isinstance(item, dict):
            return item

        for field in self.VALUE_FIELD_CANDIDATES[dimension]:
            if field in item and item[field] not in (None, ""):
                return item[field]

        if len(item) == 1:
            return next(iter(item.values()))

        return None

    def _normalize_text(self, value: Any) -> str:
        text = "" if value is None else str(value)

        text = unicodedata.normalize("NFKD", text)
        text = "".join(ch for ch in text if not unicodedata.combining(ch))
        text = text.casefold()
        text = re.sub(r"[^a-z0-9]+", " ", text)
        text = re.sub(r"\s+", " ", text).strip()

        return text

    def _normalize_compact(self, value: Any) -> str:
        return re.sub(r"[^a-z0-9]+", "", self._normalize_text(value))

    def _safe_float(self, value: Any, default: float = 0.0) -> float:
        try:
            if value is None:
                return default
            return float(value)
        except (TypeError, ValueError):
            return default

    def _safe_int(self, value: Any, default: int = 0) -> int:
        try:
            if value is None:
                return default
            return int(value)
        except (TypeError, ValueError):
            return default

    def _levenshtein_distance(
        self,
        left: str,
        right: str,
        max_distance: int | None = None,
    ) -> int:
        if left == right:
            return 0

        if not left:
            return len(right)

        if not right:
            return len(left)

        if len(left) > len(right):
            left, right = right, left

        if max_distance is not None and abs(len(left) - len(right)) > max_distance:
            return max_distance + 1

        previous_row = list(range(len(left) + 1))

        for right_index, right_char in enumerate(right, start=1):
            current_row = [right_index]
            row_min = current_row[0]

            for left_index, left_char in enumerate(left, start=1):
                insert_cost = current_row[left_index - 1] + 1
                delete_cost = previous_row[left_index] + 1
                replace_cost = previous_row[left_index - 1] + (
                    0 if left_char == right_char else 1
                )

                cost = min(insert_cost, delete_cost, replace_cost)
                current_row.append(cost)
                row_min = min(row_min, cost)

            if max_distance is not None and row_min > max_distance:
                return max_distance + 1

            previous_row = current_row

        return previous_row[-1]

    def _similarity_score(self, left: str, right: str) -> float:
        if not left or not right:
            return 0.0

        if left == right:
            return 1.0

        return SequenceMatcher(None, left, right).ratio()

    def _dynamic_fuzzy_thresholds(self, query_compact: str) -> tuple[int, float]:
        q_len = len(query_compact)

        if q_len <= 2:
            return 0, 1.00

        if q_len <= 4:
            return 1, 0.96

        if q_len <= 8:
            return 2, 0.92

        if q_len <= 14:
            return 3, 0.88

        if q_len <= 24:
            return 4, 0.84

        return 5, 0.82

    def _is_fuzzy_match(
        self,
        value_compact: str,
        query_compact: str,
    ) -> tuple[bool, int, float, int]:
        if not value_compact or not query_compact:
            return False, 999, 0.0, 999

        q_len = len(query_compact)
        length_delta = abs(len(value_compact) - len(query_compact))
        max_edit_distance, min_similarity_score = self._dynamic_fuzzy_thresholds(
            query_compact
        )

        if q_len < 3:
            return False, 999, 0.0, length_delta

        edit_distance = self._levenshtein_distance(
            value_compact,
            query_compact,
            max_distance=max_edit_distance + 2,
        )

        similarity_score = self._similarity_score(value_compact, query_compact)

        is_match = (
            edit_distance <= max_edit_distance
            or (
                q_len >= 6
                and similarity_score >= min_similarity_score
                and length_delta <= max_edit_distance + 2
            )
        )

        return is_match, edit_distance, similarity_score, length_delta

    def _extract_score(self, item: Any) -> Any:
        if not isinstance(item, dict):
            return None

        for field in self.SCORE_FIELD_CANDIDATES:
            if field in item and item[field] not in (None, ""):
                return item[field]

        match_type = str(item.get("match_type") or "").strip().lower()
        if match_type == "exact":
            return 1.00
        if match_type == "starts_with":
            return 0.95
        if match_type == "contains":
            return 0.90
        if match_type == "included":
            return 0.85
        if match_type == "fuzzy":
            return item.get("similarity_score", 0.0)

        return None

    def _extract_match_type(
        self,
        item: Any,
        value: Any,
        query: str,
    ) -> str:
        if isinstance(item, dict):
            match_type = str(item.get("match_type") or "").strip().lower()
            if match_type in self.MATCH_RANK:
                return match_type

        value_text = self._normalize_text(value)
        value_compact = self._normalize_compact(value)
        query_text = self._normalize_text(query)
        query_compact = self._normalize_compact(query)

        if not query_compact:
            return "none"

        if value_text == query_text or value_compact == query_compact:
            return "exact"

        if value_text.startswith(query_text) or value_compact.startswith(query_compact):
            return "starts_with"

        if query_text in value_text or query_compact in value_compact:
            return "contains"

        if value_text in query_text or value_compact in query_compact:
            return "included"

        fuzzy_match, _, _, _ = self._is_fuzzy_match(
            value_compact=value_compact,
            query_compact=query_compact,
        )

        if fuzzy_match:
            return "fuzzy"

        return "none"

    def _is_metric_term_sent_as_media(
        self,
        dimension: str,
        query: str,
    ) -> bool:
        if dimension != "media":
            return False

        query_compact = self._normalize_compact(query)
        return query_compact in self.METRIC_TERMS_COMPACT

    def _normalize_candidates(
        self,
        rows: list[Any],
        dimension: str,
        query: str,
    ) -> list[dict[str, Any]]:
        candidates: list[dict[str, Any]] = []
        seen: set[str] = set()

        query_compact = self._normalize_compact(query)

        if not query_compact:
            return []

        if self._is_metric_term_sent_as_media(dimension, query):
            return []

        for item in rows:
            value = self._extract_candidate_value(item, dimension)

            if value in (None, ""):
                continue

            normalized_value = self._normalize_text(value)
            normalized_compact = self._normalize_compact(value)

            if not normalized_compact:
                continue

            if normalized_compact in seen:
                continue

            seen.add(normalized_compact)

            match_type = self._extract_match_type(item, value, query)

            if match_type == "none":
                continue

            fallback_fuzzy_match, fallback_edit_distance, fallback_similarity, fallback_length_delta = (
                self._is_fuzzy_match(
                    value_compact=normalized_compact,
                    query_compact=query_compact,
                )
            )

            if isinstance(item, dict):
                edit_distance = self._safe_int(
                    item.get("edit_distance"),
                    fallback_edit_distance,
                )
                similarity_score = self._safe_float(
                    item.get("similarity_score"),
                    fallback_similarity,
                )
                length_delta = self._safe_int(
                    item.get("length_delta"),
                    fallback_length_delta,
                )
            else:
                edit_distance = fallback_edit_distance
                similarity_score = fallback_similarity
                length_delta = fallback_length_delta

            score = self._extract_score(item)

            if score is None:
                if match_type == "exact":
                    score = 1.00
                elif match_type == "starts_with":
                    score = 0.95
                elif match_type == "contains":
                    score = 0.90
                elif match_type == "included":
                    score = 0.85
                elif match_type == "fuzzy":
                    score = similarity_score
                else:
                    score = 0.0

            candidate: dict[str, Any] = {
                "value": value,
                "normalized_value": normalized_value,
                "normalized_compact": normalized_compact,
                "match_type": match_type,
                "exact_match": match_type == "exact",
                "score": self._safe_float(score),
                "edit_distance": edit_distance,
                "similarity_score": similarity_score,
                "length_delta": length_delta,
            }

            if isinstance(item, dict):
                for field in (
                    "row_count",
                    "total_media_net_eur",
                    "match_rank",
                    "max_edit_distance",
                    "min_similarity_score",
                ):
                    if field in item:
                        candidate[field] = item[field]

                if self.include_metadata:
                    candidate["raw"] = item

            elif self.include_metadata:
                candidate["raw"] = item

            candidates.append(candidate)

        candidates.sort(
            key=lambda candidate: (
                self.MATCH_RANK.get(str(candidate.get("match_type") or ""), 99),
                self._safe_float(candidate.get("edit_distance"), 999.0),
                -self._safe_float(candidate.get("similarity_score")),
                self._safe_float(candidate.get("length_delta"), 999.0),
                -self._safe_float(candidate.get("score")),
                -self._safe_float(candidate.get("row_count")),
                -self._safe_float(candidate.get("total_media_net_eur")),
                str(candidate.get("value") or ""),
            )
        )

        return candidates

    def _error_response(
        self,
        dimension: str | None,
        q: str | None,
        error_type: str,
        message: str,
    ) -> Data:
        payload = {
            "ok": False,
            "tool": self.name,
            "dimension": dimension,
            "q": q,
            "normalized_q": self._normalize_text(q),
            "normalized_q_compact": self._normalize_compact(q),
            "resolution_status": "error",
            "canonical_value": None,
            "candidates": [],
            "count": 0,
            "error_type": error_type,
            "error": message,
        }

        self.status = payload
        return Data(data=payload)

    def _build_success_response(
        self,
        *,
        dimension: str,
        raw_query: str,
        candidates: list[dict[str, Any]],
    ) -> dict[str, Any]:
        exact_matches = [
            candidate
            for candidate in candidates
            if candidate.get("exact_match")
        ]

        if exact_matches:
            canonical_value = exact_matches[0]["value"]
            resolution_status = "exact_match"

        elif len(candidates) == 1:
            canonical_value = candidates[0]["value"]
            resolution_status = "single_candidate"

        elif len(candidates) > 1:
            first = candidates[0]
            second = candidates[1]

            first_rank = self.MATCH_RANK.get(
                str(first.get("match_type") or ""),
                99,
            )
            second_rank = self.MATCH_RANK.get(
                str(second.get("match_type") or ""),
                99,
            )

            first_score = self._safe_float(first.get("score"))
            second_score = self._safe_float(second.get("score"))

            first_edit_distance = self._safe_float(
                first.get("edit_distance"),
                999.0,
            )
            second_edit_distance = self._safe_float(
                second.get("edit_distance"),
                999.0,
            )

            has_clear_rank_gap = first_rank < second_rank
            has_clear_score_gap = (
                first_score >= self.AUTO_SELECT_MIN_SCORE
                and first_score - second_score >= self.AUTO_SELECT_MIN_GAP
            )
            has_clear_distance_gap = (
                first_edit_distance < second_edit_distance
                and first_score >= self.AUTO_SELECT_MIN_SCORE
            )

            if has_clear_rank_gap or has_clear_score_gap or has_clear_distance_gap:
                canonical_value = first["value"]
                resolution_status = "auto_selected"
            else:
                canonical_value = None
                resolution_status = "ambiguous"

        else:
            canonical_value = None
            resolution_status = "not_found"

        return {
            "ok": True,
            "tool": self.name,
            "dimension": dimension,
            "q": raw_query,
            "normalized_q": self._normalize_text(raw_query),
            "normalized_q_compact": self._normalize_compact(raw_query),
            "resolution_status": resolution_status,
            "canonical_value": canonical_value,
            "candidates": candidates,
            "count": len(candidates),
        }

    def resolve_value(self) -> Data:
        raw_query = (self.q or "").strip()

        if not raw_query:
            return self._error_response(
                None,
                raw_query,
                "missing_query",
                "Input q is required.",
            )

        try:
            dimension = self._normalize_dimension(self.dimension)
        except ValueError as exc:
            return self._error_response(
                None,
                raw_query,
                "invalid_dimension",
                str(exc),
            )

        if self._is_metric_term_sent_as_media(dimension, raw_query):
            result = {
                "ok": True,
                "tool": self.name,
                "dimension": dimension,
                "q": raw_query,
                "normalized_q": self._normalize_text(raw_query),
                "normalized_q_compact": self._normalize_compact(raw_query),
                "resolution_status": "not_found",
                "canonical_value": None,
                "candidates": [],
                "count": 0,
                "warning": (
                    "The provided value looks like a metric, "
                    "not a media filter."
                ),
            }

            self.status = f"{dimension}: not_found (metric term sent as media)"
            return Data(data=result)

        endpoint = self.DIMENSION_TO_ENDPOINT[dimension]
        limit = self._safe_limit()
        url = self._build_url(endpoint, raw_query, limit)
        timeout_seconds = float(self.timeout or 30)

        try:
            with httpx.Client(
                timeout=timeout_seconds,
                follow_redirects=False,
            ) as client:
                response = client.get(
                    url,
                    headers={"User-Agent": "Langflow/1.0"},
                )

            try:
                payload = response.json()
            except ValueError:
                return self._error_response(
                    dimension,
                    raw_query,
                    "invalid_json",
                    (
                        "Rill returned non-JSON response with "
                        f"HTTP {response.status_code}."
                    ),
                )

            if response.status_code >= 400:
                return self._error_response(
                    dimension,
                    raw_query,
                    "http_error",
                    f"Rill returned HTTP {response.status_code}: {payload}",
                )

        except httpx.TimeoutException:
            return self._error_response(
                dimension,
                raw_query,
                "timeout",
                f"Rill request timed out after {timeout_seconds:g}s.",
            )

        except httpx.RequestError as exc:
            return self._error_response(
                dimension,
                raw_query,
                "request_error",
                str(exc),
            )

        rows = self._extract_rows(payload)
        candidates = self._normalize_candidates(rows, dimension, raw_query)

        result = self._build_success_response(
            dimension=dimension,
            raw_query=raw_query,
            candidates=candidates,
        )

        if self.include_metadata:
            result["metadata"] = {
                "endpoint": endpoint,
                "url": url,
                "http_status": response.status_code,
                "limit": limit,
                "raw_payload": payload,
            }

        self.status = (
            f"{dimension}: {result['resolution_status']} "
            f"({len(candidates)} candidates)"
        )

        return Data(data=result)

from __future__ import annotations

import json
import re
import unicodedata
from typing import Any
from urllib.parse import urlencode

import httpx

from lfx.custom.custom_component.component import Component
from lfx.inputs.inputs import BoolInput, HandleInput
from lfx.io import IntInput, MessageTextInput, Output
from lfx.schema.data import Data


class BudgetFilterResolver(Component):
    display_name = "Budget Filter Resolver"
    description = (
        "Resolves concrete user-provided budget filters against Rill canonical values. "
        "Stops the pipeline with clarification_needed when a filter is ambiguous or not found."
    )
    documentation: str = "https://docs.langflow.org/components-custom-components"
    icon = "SearchCheck"
    name = "BudgetFilterResolver"

    DEFAULT_API_BASE = (
        "http://rillcontacts-rill.n8n.svc.cluster.local:9009"
        "/v1/instances/default/api"
    )

    DIMENSION_TO_RESOLVE_ENDPOINT = {
        "brand": "resolve_brand",
        "country": "resolve_country",
        "media": "resolve_media",
        "status": "resolve_status",
        "workflow_process": "resolve_workflow",
    }

    DIMENSION_TO_FILTER_ENDPOINT = {
        "brand": "filter_brands",
        "country": "filter_countries",
        "media": "filter_media",
        "status": "filter_statuses",
        "workflow_process": "filter_workflows",
    }

    VALUE_FIELD_CANDIDATES = {
        "brand": ["brand", "brand_name", "value", "label", "name"],
        "country": ["country", "country_name", "value", "label", "name"],
        "media": ["media", "media_name", "value", "label", "name"],
        "status": ["status", "value", "label", "name"],
        "workflow_process": [
            "workflow_process",
            "workflow",
            "process",
            "value",
            "label",
            "name",
        ],
    }

    FILTER_TO_QUERY_FIELD = {
        "brand": "brand",
        "country": "country",
        "media": "media",
        "status": "status_filter",
        "workflow_process": "workflow_process",
    }

    inputs = [
        HandleInput(
            name="input_value",
            display_name="Parsed Budget Intent",
            info=(
                "Data/JSON output from BudgetIntentionParser. "
                "Connect BudgetIntentionParser.parsed_intent here."
            ),
            input_types=["Data", "JSON", "Message"],
            required=True,
        ),
        MessageTextInput(
            name="base_url",
            display_name="Rill API Base URL",
            info="Base Rill API URL without endpoint name.",
            value=DEFAULT_API_BASE,
            advanced=True,
        ),
        IntInput(
            name="resolve_limit",
            display_name="Resolve Limit",
            info="Maximum candidates returned by resolve_* endpoints.",
            value=10,
            advanced=True,
        ),
        IntInput(
            name="examples_limit",
            display_name="Examples Limit",
            info="Maximum examples returned when resolution fails.",
            value=20,
            advanced=True,
        ),
        IntInput(
            name="timeout",
            display_name="Timeout Seconds",
            info="HTTP timeout in seconds.",
            value=30,
            advanced=True,
        ),
        BoolInput(
            name="include_metadata",
            display_name="Include Metadata",
            info="Include URLs, HTTP status and raw Rill payloads for debugging.",
            value=False,
            advanced=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Resolved Budget Intent",
            name="resolved_intent",
            method="resolve_filters",
        ),
    ]

    def resolve_filters(self) -> Data:
        intent = self._extract_payload(self.input_value)

        warnings: list[str] = list(intent.get("warnings") or [])
        errors: list[dict[str, Any]] = list(intent.get("errors") or [])
        metadata: dict[str, Any] = {"resolve_calls": [], "example_calls": []}

        if not isinstance(intent, dict):
            result = self._error_result(
                message="BudgetFilterResolver expected a dict/Data payload from BudgetIntentionParser.",
                error_type="invalid_input",
            )
            self.status = result
            return Data(data=result)

        filters = intent.get("filters") or []

        if not isinstance(filters, list):
            filters = []
            warnings.append("Intent filters field was not a list. Ignored.")

        # No concrete filters => pass-through.
        if not filters:
            result = {
                **intent,
                "component": "BudgetFilterResolver",
                "status": "ok",
                "ok": True,
                "resolved_filters": [],
                "query_filters": self._empty_query_filters(),
                "clarification": {},
                "warnings": warnings,
                "errors": errors,
            }

            if self.include_metadata:
                result["metadata"] = metadata

            self.status = "No filters to resolve"
            return Data(data=result)

        resolved_filters: list[dict[str, Any]] = []
        query_filters = self._empty_query_filters()

        for item in filters:
            dimension = str(item.get("dimension") or "").strip()
            source_value = str(item.get("source_value") or "").strip()

            if not dimension or not source_value:
                warnings.append(f"Ignored invalid filter: {item}")
                continue

            if dimension not in self.DIMENSION_TO_RESOLVE_ENDPOINT:
                warnings.append(f"Ignored unsupported filter dimension '{dimension}'.")
                continue

            resolution = self._resolve_one(
                dimension=dimension,
                source_value=source_value,
                metadata=metadata,
            )

            status = resolution.get("resolution_status")

            if status in {"exact_match", "single_candidate"}:
                canonical_value = resolution.get("canonical_value")

                resolved_filter = {
                    "dimension": dimension,
                    "source_value": source_value,
                    "canonical_value": canonical_value,
                    "resolution_status": status,
                }

                resolved_filters.append(resolved_filter)

                query_field = self.FILTER_TO_QUERY_FIELD[dimension]
                query_filters[query_field] = canonical_value or ""

                if canonical_value and canonical_value.casefold() != source_value.casefold():
                    warnings.append(
                        f"Resolved {dimension} '{source_value}' to canonical value '{canonical_value}'."
                    )

                continue

            # Stop at first ambiguous/unresolved filter.
            clarification = {
                "dimension": dimension,
                "source_value": source_value,
                "options": resolution.get("candidates") or [],
            }

            result = {
                **intent,
                "component": "BudgetFilterResolver",
                "status": "clarification_needed",
                "ok": False,
                "resolved_filters": resolved_filters,
                "query_filters": query_filters,
                "clarification": clarification,
                "warnings": warnings,
                "errors": errors,
            }

            if self.include_metadata:
                result["metadata"] = metadata

            self.status = f"clarification_needed: {dimension}={source_value}"
            return Data(data=result)

        result = {
            **intent,
            "component": "BudgetFilterResolver",
            "status": "ok",
            "ok": True,
            "resolved_filters": resolved_filters,
            "query_filters": query_filters,
            "clarification": {},
            "warnings": warnings,
            "errors": errors,
        }

        if self.include_metadata:
            result["metadata"] = metadata

        self.status = f"Resolved {len(resolved_filters)} filter(s)"
        return Data(data=result)

    # -----------------------------
    # Rill calls
    # -----------------------------

    def _resolve_one(
        self,
        *,
        dimension: str,
        source_value: str,
        metadata: dict[str, Any],
    ) -> dict[str, Any]:
        endpoint = self.DIMENSION_TO_RESOLVE_ENDPOINT[dimension]
        url = self._build_url(
            endpoint=endpoint,
            params={
                "q": source_value,
                "limit": self._safe_int(self.resolve_limit, default=10, minimum=1, maximum=50),
            },
        )

        payload, http_meta, error = self._get_json(url)
        metadata["resolve_calls"].append(http_meta)

        if error:
            examples = self._get_examples(dimension, metadata)
            return {
                "resolution_status": "not_found",
                "canonical_value": None,
                "candidates": examples,
                "error": error,
            }

        normalized = self._normalize_resolve_payload(
            payload=payload,
            dimension=dimension,
            source_value=source_value,
        )

        if normalized.get("resolution_status") == "not_found":
            examples = self._get_examples(dimension, metadata)
            normalized["candidates"] = examples

        return normalized

    def _get_examples(
        self,
        dimension: str,
        metadata: dict[str, Any],
    ) -> list[dict[str, Any]]:
        endpoint = self.DIMENSION_TO_FILTER_ENDPOINT[dimension]
        url = self._build_url(
            endpoint=endpoint,
            params={
                "limit": self._safe_int(self.examples_limit, default=20, minimum=1, maximum=100),
            },
        )

        payload, http_meta, error = self._get_json(url)
        metadata["example_calls"].append(http_meta)

        if error:
            return []

        rows = self._extract_rows(payload)
        output: list[dict[str, Any]] = []

        for row in rows[: self._safe_int(self.examples_limit, default=20, minimum=1, maximum=100)]:
            value = self._extract_value(row, dimension)

            if value is None or str(value).strip() == "":
                continue

            option = {
                "value": str(value).strip(),
                "match_type": None,
                "row_count": self._extract_row_count(row),
            }
            output.append(option)

        return output

    def _get_json(self, url: str) -> tuple[Any, dict[str, Any], dict[str, Any] | None]:
        timeout_seconds = float(self.timeout or 30)

        http_meta: dict[str, Any] = {
            "url": url,
            "http_status": None,
        }

        try:
            with httpx.Client(timeout=timeout_seconds, follow_redirects=False) as client:
                response = client.get(url, headers={"User-Agent": "Langflow/1.0"})

            http_meta["http_status"] = response.status_code

            try:
                payload = response.json()
            except ValueError:
                return (
                    None,
                    http_meta,
                    {
                        "type": "invalid_json",
                        "message": f"Rill returned non-JSON response with HTTP {response.status_code}.",
                    },
                )

            if response.status_code >= 400:
                return (
                    payload,
                    http_meta,
                    {
                        "type": "http_error",
                        "message": f"Rill returned HTTP {response.status_code}: {payload}",
                    },
                )

            if self.include_metadata:
                http_meta["raw_payload"] = payload

            return payload, http_meta, None

        except httpx.TimeoutException:
            return (
                None,
                http_meta,
                {
                    "type": "timeout",
                    "message": f"Rill request timed out after {timeout_seconds:g}s.",
                },
            )

        except httpx.RequestError as exc:
            return (
                None,
                http_meta,
                {
                    "type": "request_error",
                    "message": str(exc),
                },
            )

    # -----------------------------
    # Resolution normalization
    # -----------------------------

    def _normalize_resolve_payload(
        self,
        *,
        payload: Any,
        dimension: str,
        source_value: str,
    ) -> dict[str, Any]:
        # Case 1: your existing resolve_* API already returns the desired contract.
        if isinstance(payload, dict) and "resolution_status" in payload:
            candidates = self._normalize_candidates(
                payload.get("candidates") or payload.get("matches") or [],
                dimension,
            )

            status = payload.get("resolution_status")
            canonical_value = payload.get("canonical_value") or payload.get("value")

            if status in {"exact_match", "single_candidate"} and canonical_value:
                return {
                    "resolution_status": status,
                    "canonical_value": str(canonical_value).strip(),
                    "candidates": candidates,
                }

            if status == "ambiguous":
                return {
                    "resolution_status": "ambiguous",
                    "canonical_value": None,
                    "candidates": candidates,
                }

            return {
                "resolution_status": "not_found",
                "canonical_value": None,
                "candidates": candidates,
            }

        # Case 2: Rill returns rows/items/values and resolver decides locally.
        rows = self._extract_rows(payload)
        candidates = self._normalize_candidates(rows, dimension)

        if not candidates:
            return {
                "resolution_status": "not_found",
                "canonical_value": None,
                "candidates": [],
            }

        source_norm = self._normalize_text(source_value)

        exact = [
            candidate for candidate in candidates
            if self._normalize_text(candidate.get("value")) == source_norm
        ]

        if len(exact) == 1:
            return {
                "resolution_status": "exact_match",
                "canonical_value": exact[0]["value"],
                "candidates": exact,
            }

        if len(candidates) == 1:
            return {
                "resolution_status": "single_candidate",
                "canonical_value": candidates[0]["value"],
                "candidates": candidates,
            }

        return {
            "resolution_status": "ambiguous",
            "canonical_value": None,
            "candidates": candidates,
        }

    def _normalize_candidates(
        self,
        rows: Any,
        dimension: str,
    ) -> list[dict[str, Any]]:
        output: list[dict[str, Any]] = []

        for row in self._extract_rows(rows):
            value = self._extract_value(row, dimension)

            if value is None or str(value).strip() == "":
                continue

            option = {
                "value": str(value).strip(),
                "match_type": self._extract_match_type(row),
                "row_count": self._extract_row_count(row),
            }

            output.append(option)

        return self._dedupe_candidates(output)

    # -----------------------------
    # Payload / URL helpers
    # -----------------------------

    def _extract_payload(self, value: Any) -> dict[str, Any]:
        if isinstance(value, Data):
            return value.data if isinstance(value.data, dict) else {}

        data = getattr(value, "data", None)
        if isinstance(data, dict):
            return data

        text = getattr(value, "text", None)
        if isinstance(text, str):
            return self._loads_json(text)

        content = getattr(value, "content", None)
        if isinstance(content, str):
            return self._loads_json(content)

        if isinstance(value, dict):
            return value

        if isinstance(value, str):
            return self._loads_json(value)

        return {}

    def _loads_json(self, text: str) -> dict[str, Any]:
        text = (text or "").strip()

        if not text:
            return {}

        try:
            payload = json.loads(text)
            return payload if isinstance(payload, dict) else {}
        except Exception:
            pass

        start = text.find("{")
        end = text.rfind("}")

        if start >= 0 and end > start:
            try:
                payload = json.loads(text[start : end + 1])
                return payload if isinstance(payload, dict) else {}
            except Exception:
                return {}

        return {}

    def _build_url(self, *, endpoint: str, params: dict[str, Any]) -> str:
        base_url = (self.base_url or self.DEFAULT_API_BASE).strip().rstrip("/")
        query = urlencode({k: v for k, v in params.items() if v not in (None, "")})
        return f"{base_url}/{endpoint}?{query}" if query else f"{base_url}/{endpoint}"

    def _extract_rows(self, payload: Any) -> list[Any]:
        if isinstance(payload, dict):
            for key in ("result", "data", "rows", "values", "items", "matches", "candidates"):
                value = payload.get(key)

                if isinstance(value, list):
                    return value

                if value is not None:
                    return [value]

            return [payload]

        if isinstance(payload, list):
            return payload

        if payload is None:
            return []

        return [payload]

    def _extract_value(self, row: Any, dimension: str) -> Any:
        if not isinstance(row, dict):
            return row

        for field in self.VALUE_FIELD_CANDIDATES[dimension]:
            value = row.get(field)

            if value not in (None, ""):
                return value

        return None

    def _extract_match_type(self, row: Any) -> str | None:
        if not isinstance(row, dict):
            return None

        for key in ("match_type", "match", "resolution_type"):
            value = row.get(key)

            if value not in (None, ""):
                return str(value)

        return None

    def _extract_row_count(self, row: Any) -> int | None:
        if not isinstance(row, dict):
            return None

        value = row.get("row_count")

        if value is None:
            return None

        try:
            return int(value)
        except Exception:
            return None

    def _empty_query_filters(self) -> dict[str, str]:
        return {
            "brand": "",
            "country": "",
            "media": "",
            "status_filter": "",
            "workflow_process": "",
        }

    def _safe_int(
        self,
        value: Any,
        *,
        default: int,
        minimum: int,
        maximum: int,
    ) -> int:
        try:
            number = int(value)
        except Exception:
            number = default

        return max(minimum, min(number, maximum))

    def _normalize_text(self, value: Any) -> str:
        text = "" if value is None else str(value)
        text = unicodedata.normalize("NFKD", text)
        text = "".join(ch for ch in text if not unicodedata.combining(ch))
        text = text.casefold()
        text = re.sub(r"[^a-z0-9]+", " ", text)
        text = re.sub(r"\s+", " ", text).strip()
        return text

    def _dedupe_candidates(self, candidates: list[dict[str, Any]]) -> list[dict[str, Any]]:
        seen: set[str] = set()
        output: list[dict[str, Any]] = []

        for item in candidates:
            value = str(item.get("value") or "").strip()

            if not value:
                continue

            key = self._normalize_text(value)

            if key in seen:
                continue

            seen.add(key)
            output.append(item)

        return output

    def _error_result(self, *, message: str, error_type: str) -> dict[str, Any]:
        return {
            "component": "BudgetFilterResolver",
            "status": "error",
            "ok": False,
            "resolved_filters": [],
            "query_filters": self._empty_query_filters(),
            "clarification": {},
            "warnings": [],
            "errors": [
                {
                    "type": error_type,
                    "message": message,
                }
            ],
        }

from __future__ import annotations

import json
from typing import Any
from urllib.parse import urlencode

import httpx

from lfx.custom.custom_component.component import Component
from lfx.inputs.inputs import BoolInput, HandleInput
from lfx.io import IntInput, MessageTextInput, Output
from lfx.schema.data import Data


class BudgetQueryExecutor(Component):
    display_name = "Budget Query Executor"
    description = (
