    def execute_query(self) -> Data:
        payload = self._extract_payload(self.input_value)

        if not isinstance(payload, dict) or not payload:
            result = self._error_result(
                error_type="invalid_input",
                message="BudgetQueryExecutor expected a Data/JSON payload from BudgetFilterResolver.",
            )
            self.status = result
            return Data(data=result)

        upstream_status = payload.get("status")

        # Stop early. Do not call Rill when resolver already needs clarification.
        if upstream_status == "clarification_needed":
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "query_executed": False,
                "rill_result": None,
            }
            self.status = "Skipped: clarification_needed"
            return Data(data=result)

        if payload.get("ok") is False and upstream_status != "ok":
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "query_executed": False,
                "rill_result": None,
            }
            self.status = f"Skipped: upstream status={upstream_status}"
            return Data(data=result)

        warnings = list(payload.get("warnings") or [])
        errors = list(payload.get("errors") or [])

        task_type = payload.get("task_type") or "query"
        report_type = payload.get("report_type")
        metric = payload.get("metric") or "media_net"

        if task_type == "list_values":
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "status": "unsupported",
                "ok": False,
                "query_executed": False,
                "rill_result": None,
                "warnings": warnings,
                "errors": errors
                + [
                    {
                        "type": "unsupported_task",
                        "message": (
                            "task_type=list_values must be handled by a dedicated "
                            "BudgetFilterValuesExecutor component, not by BudgetQueryExecutor."
                        ),
                    }
                ],
            }
            self.status = "Unsupported: list_values"
            return Data(data=result)

        if task_type == "pivot":
            # Important: pivot is not formatted here.
            # This component only fetches source data.
            warnings.append(
                "task_type=pivot detected. BudgetQueryExecutor will only fetch source data. "
                "Pivot transformation must be handled by BudgetPivotTransformer."
            )

        if report_type not in self.ALLOWED_REPORT_TYPES:
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "status": "error",
                "ok": False,
                "query_executed": False,
                "rill_result": None,
                "warnings": warnings,
                "errors": errors
                + [
                    {
                        "type": "invalid_report_type",
                        "message": f"Unsupported or missing report_type: {report_type}",
                    }
                ],
            }
            self.status = f"Invalid report_type={report_type}"
            return Data(data=result)

        if metric not in self.ALLOWED_METRICS:
            warnings.append(f"Unsupported metric '{metric}', defaulted to media_net.")
            metric = "media_net"

        query_filters = self._build_query_filters(payload)

        if report_type == "brand_detail" and not query_filters.get("brand"):
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "status": "clarification_needed",
                "ok": False,
                "query_executed": False,
                "rill_result": None,
                "clarification": {
                    "dimension": "brand",
                    "source_value": None,
                    "options": [],
                    "message": "Le détail financier d'une marque nécessite une marque précise.",
                },
                "warnings": warnings,
                "errors": errors,
            }
            self.status = "Missing brand for brand_detail"
            return Data(data=result)

        limit = self._normalize_limit(payload.get("limit"))

        request_payload = {
            "report_type": report_type,
            "metric": metric,
            "brand": query_filters.get("brand", ""),
            "country": query_filters.get("country", ""),
            "media": query_filters.get("media", ""),
            "status_filter": query_filters.get("status_filter", ""),
            "workflow_process": query_filters.get("workflow_process", ""),
            "limit": limit,
        }

        endpoint_mapping = self._load_endpoint_mapping()
        endpoint = endpoint_mapping.get(report_type)

        if not endpoint:
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "status": "error",
                "ok": False,
                "query_executed": False,
                "rill_result": None,
                "request": request_payload,
                "warnings": warnings,
                "errors": errors
                + [
                    {
                        "type": "missing_endpoint_mapping",
                        "message": f"No endpoint mapping found for report_type={report_type}.",
                    }
                ],
            }
            self.status = f"Missing endpoint for {report_type}"
            return Data(data=result)

        url = self._build_url(endpoint=endpoint, params=request_payload)
        rill_payload, http_meta, error = self._get_json(url)

        request_metadata = {
            "endpoint": endpoint,
            "url": url,
            "params": request_payload,
            "http": http_meta,
        }

        if error:
            result = {
                **payload,
                "component": "BudgetQueryExecutor",
                "status": "error",
                "ok": False,
                "query_executed": True,
                "request": request_payload,
                "rill_result": {
                    "ok": False,
                    "rows": [],
                    "row_count": 0,
                    "error": error,
                },
                "warnings": warnings,
                "errors": errors + [error],
            }

            if self.include_request_metadata:
                result["request_metadata"] = request_metadata

            self.status = f"Rill error: {error.get('type')}"
            return Data(data=result)

        rows = self._extract_rows(rill_payload)

        normalized_result = {
            "ok": True,
            "rows": rows,
            "row_count": len(rows),
        }

        if self.include_raw_response:
            normalized_result["raw"] = rill_payload

        status = "ok" if rows else "empty"

        if not rows:
            warnings.append("Rill returned ok=true but no usable rows were found.")

        result = {
            **payload,
            "component": "BudgetQueryExecutor",
            "status": status,
            "ok": True,
            "query_executed": True,
            "request": request_payload,
            "rill_result": normalized_result,
            "warnings": warnings,
            "errors": errors,
        }

        if self.include_request_metadata:
            result["request_metadata"] = request_metadata

        self.status = f"{report_type}: {len(rows)} row(s)"
        return Data(data=result)

    # -----------------------------
    # Input / payload helpers
    # -----------------------------

    def _extract_payload(self, value: Any) -> dict[str, Any]:
        if isinstance(value, Data):
            return value.data if isinstance(value.data, dict) else {}

        data = getattr(value, "data", None)
        if isinstance(data, dict):
            return data

        if isinstance(value, dict):
            return value

        text = getattr(value, "text", None)
        if isinstance(text, str):
            return self._loads_json(text)

        content = getattr(value, "content", None)
        if isinstance(content, str):
            return self._loads_json(content)

        if isinstance(value, str):
            return self._loads_json(value)

        return {}

    def _loads_json(self, text: str) -> dict[str, Any]:
        text = (text or "").strip()

        if not text:
            return {}

        try:
            obj = json.loads(text)
            return obj if isinstance(obj, dict) else {}
        except Exception:
            pass

        start = text.find("{")
        end = text.rfind("}")

        if start >= 0 and end > start:
            try:
                obj = json.loads(text[start : end + 1])
                return obj if isinstance(obj, dict) else {}
            except Exception:
                return {}

        return {}

    def _build_query_filters(self, payload: dict[str, Any]) -> dict[str, str]:
        query_filters = payload.get("query_filters")

        if isinstance(query_filters, dict):
            return {
                "brand": str(query_filters.get("brand") or ""),
                "country": str(query_filters.get("country") or ""),
                "media": str(query_filters.get("media") or ""),
                "status_filter": str(query_filters.get("status_filter") or ""),
                "workflow_process": str(query_filters.get("workflow_process") or ""),
            }

        output = {
            "brand": "",
            "country": "",
            "media": "",
            "status_filter": "",
            "workflow_process": "",
        }

        for item in payload.get("resolved_filters") or []:
            if not isinstance(item, dict):
                continue

            dimension = item.get("dimension")
            canonical_value = item.get("canonical_value")

            if not canonical_value:
                continue

            if dimension == "brand":
                output["brand"] = str(canonical_value)
            elif dimension == "country":
                output["country"] = str(canonical_value)
            elif dimension == "media":
                output["media"] = str(canonical_value)
            elif dimension == "status":
                output["status_filter"] = str(canonical_value)
            elif dimension == "workflow_process":
                output["workflow_process"] = str(canonical_value)

        return output

    def _normalize_limit(self, value: Any) -> int:
        default_limit = self._safe_int(self.default_limit, default=15, minimum=1, maximum=100)
        max_limit = self._safe_int(self.max_limit, default=100, minimum=1, maximum=500)

        if value in (None, "", "null", "None"):
            return min(default_limit, max_limit)

        try:
            limit = int(value)
        except Exception:
            return min(default_limit, max_limit)

        if limit <= 0:
            return min(default_limit, max_limit)

        return min(limit, max_limit)

    def _load_endpoint_mapping(self) -> dict[str, str]:
        raw = self.endpoint_mapping_json or ""

        try:
            parsed = json.loads(raw)
            if isinstance(parsed, dict):
                mapping = dict(self.DEFAULT_ENDPOINT_MAPPING)
                mapping.update(
                    {
                        str(key): str(value)
                        for key, value in parsed.items()
                        if value is not None and str(value).strip()
                    }
                )
                return mapping
        except Exception:
            pass

        return dict(self.DEFAULT_ENDPOINT_MAPPING)

    def _safe_int(
        self,
        value: Any,
        *,
        default: int,
        minimum: int,
        maximum: int,
    ) -> int:
        try:
            number = int(value)
        except Exception:
            number = default

        return max(minimum, min(number, maximum))

    # -----------------------------
    # HTTP / Rill helpers
    # -----------------------------

    def _build_url(self, *, endpoint: str, params: dict[str, Any]) -> str:
        base_url = (self.base_url or self.DEFAULT_API_BASE).strip().rstrip("/")
        clean_params = {
            key: value
            for key, value in params.items()
            if value is not None
        }
        return f"{base_url}/{endpoint}?{urlencode(clean_params)}"

    def _get_json(self, url: str) -> tuple[Any, dict[str, Any], dict[str, Any] | None]:
        timeout_seconds = float(self.timeout or 45)

        http_meta = {
            "url": url,
            "http_status": None,
        }

        try:
            with httpx.Client(timeout=timeout_seconds, follow_redirects=False) as client:
                response = client.get(url, headers={"User-Agent": "Langflow/1.0"})

            http_meta["http_status"] = response.status_code

            try:
                payload = response.json()
            except ValueError:
                return (
                    None,
                    http_meta,
                    {
                        "type": "invalid_json",
                        "message": f"Rill returned non-JSON response with HTTP {response.status_code}.",
                    },
                )

            if response.status_code >= 400:
                return (
                    payload,
                    http_meta,
                    {
                        "type": "http_error",
                        "message": f"Rill returned HTTP {response.status_code}: {payload}",
                    },
                )

            return payload, http_meta, None

        except httpx.TimeoutException:
            return (
                None,
                http_meta,
                {
                    "type": "timeout",
                    "message": f"Rill request timed out after {timeout_seconds:g}s.",
                },
            )

        except httpx.RequestError as exc:
            return (
                None,
                http_meta,
                {
                    "type": "request_error",
                    "message": str(exc),
                },
            )

    def _extract_rows(self, payload: Any) -> list[dict[str, Any]]:
        if payload is None:
            return []

        if isinstance(payload, list):
            return [row for row in payload if isinstance(row, dict)]

        if not isinstance(payload, dict):
            return []

        # Common Rill/custom API shapes.
        candidates = [
            payload.get("data"),
            payload.get("rows"),
            payload.get("result"),
            payload.get("items"),
            payload.get("values"),
        ]

        raw = payload.get("raw")
        if isinstance(raw, dict):
            candidates.extend(
                [
                    raw.get("data"),
                    raw.get("rows"),
                    raw.get("result"),
                    raw.get("items"),
                    raw.get("values"),
                ]
            )

        for candidate in candidates:
            if isinstance(candidate, list):
                return [row for row in candidate if isinstance(row, dict)]

            if isinstance(candidate, dict):
                nested = self._extract_rows(candidate)
                if nested:
                    return nested

        # If the API returns a single KPI object.
        if self._looks_like_data_row(payload):
            return [payload]

        return []

    def _looks_like_data_row(self, payload: dict[str, Any]) -> bool:
        technical_keys = {
            "ok",
            "status",
            "error",
            "error_type",
            "message",
            "raw",
            "data",
            "rows",
            "result",
        }

        return any(key not in technical_keys for key in payload.keys())

    def _error_result(self, *, error_type: str, message: str) -> dict[str, Any]:
        return {
            "component": "BudgetQueryExecutor",
            "status": "error",
            "ok": False,
            "query_executed": False,
            "request": None,
            "rill_result": None,
            "warnings": [],
            "errors": [
                {
                    "type": error_type,
                    "message": message,
                }
            ],
        }

