    @staticmethod
    def is_binary(file_path: str | Path) -> bool:
        try:
            with Path(file_path).open("rb") as file:
                sample = file.read(1024)
            return b"\x00" in sample
        except Exception:
            return True

    @staticmethod
    def check_file_patterns(file_path: str | Path, patterns: str) -> bool:
        if not patterns or patterns.isspace():
            return True

        path_str = str(file_path).replace("\\", "/")
        file_name = Path(path_str).name
        pattern_list = [pattern.strip() for pattern in patterns.split(",") if pattern.strip()]

        if not pattern_list:
            return True

        for pattern in pattern_list:
            if pattern.startswith("!"):
                exclude_pattern = pattern[1:].strip()
                if fnmatch(path_str, exclude_pattern) or fnmatch(file_name, exclude_pattern):
                    return False

        include_patterns = [p for p in pattern_list if not p.startswith("!")]
        if not include_patterns:
            return True

        return any(
            fnmatch(path_str, pattern) or fnmatch(file_name, pattern)
            for pattern in include_patterns
        )

    @staticmethod
    def check_content_pattern(file_path: str | Path, pattern: str) -> bool:
        try:
            with Path(file_path).open("rb") as file:
                sample = file.read(1024)
                if b"\x00" in sample:
                    return False

            content_regex = re.compile(pattern, re.MULTILINE)

            with Path(file_path).open("r", encoding="utf-8") as file:
                file_content = file.read()

            return bool(content_regex.search(file_content))
        except (OSError, UnicodeDecodeError, re.error, TypeError, ValueError):
            return False

    def _relative_path(self, file_path: str | Path, repo_path: str | Path) -> str:
        file_path = Path(file_path)
        repo_path = Path(repo_path)

        try:
            return file_path.resolve().relative_to(repo_path.resolve()).as_posix()
        except Exception:
            return file_path.as_posix().replace("\\", "/")

    def _normalize_root_folder(self, root_folder: str | None) -> str:
        root = str(root_folder or "").replace("\\", "/").strip().strip("/")
        return root

    def _skill_file_filter(self, file_path: str | Path, repo_path: str | Path, root_folder: str) -> bool:
        path = Path(file_path)

        if not path.exists() or not path.is_file():
            return False

        if self.is_binary(path):
            return False

        rel_path = self._relative_path(path, repo_path)

        if root_folder and rel_path != root_folder and not rel_path.startswith(f"{root_folder}/"):
            return False

        if not rel_path.endswith((".yaml", ".yml")):
            return False

        file_filter_patterns = getattr(self, "file_filter", None)
        if file_filter_patterns and not self.check_file_patterns(rel_path, file_filter_patterns):
            return False

        content_filter_pattern = getattr(self, "content_filter", None)
        if content_filter_pattern and not self.check_content_pattern(path, content_filter_pattern):
            return False

        return True

    def _doc_to_data(self, doc, repo_path: str | Path) -> Data:
        metadata = doc.metadata or {}
        source = metadata.get("source") or metadata.get("file_path") or ""
        rel_path = self._relative_path(source, repo_path) if source else ""

        normalized_metadata = dict(metadata)
        normalized_metadata["relative_path"] = rel_path

        return Data(
            data={
                "path": rel_path,
                "content": doc.page_content,
                "metadata": normalized_metadata,
            }
        )

    def _checkout_branch_strict(self, repo: Repo, branch: str | None) -> str | None:
        if not branch:
            try:
                return repo.active_branch.name
            except Exception:
                return None

        try:
            repo.git.checkout(branch)
            return branch
        except GitCommandError:
            remote_ref = f"origin/{branch}"
            try:
                repo.git.checkout("-B", branch, remote_ref)
                return branch
            except GitCommandError as exc:
                raise ValueError(f"Unable to checkout branch '{branch}': {exc}") from exc

    def _refresh_local_repo(self, repo_path: Path, branch: str | None) -> str | None:
        repo = Repo(str(repo_path))

        if repo.bare:
            raise ValueError(f"Local path is a bare git repository: {repo_path}")

        active_branch = self._checkout_branch_strict(repo, branch)

        if not repo.remotes:
            self.log(
                {
                    "action": "local_refresh_skipped",
                    "reason": "no_remotes",
                    "repo_path": str(repo_path),
                    "branch": active_branch,
                }
            )
            return active_branch

        remote = repo.remotes.origin if "origin" in [r.name for r in repo.remotes] else repo.remotes[0]
        target_branch = active_branch or branch or "main"

        self.log(
            {
                "action": "local_refresh_start",
                "repo_path": str(repo_path),
                "remote": remote.name,
                "branch": target_branch,
            }
        )

        remote.fetch()
        repo.git.reset("--hard", f"{remote.name}/{target_branch}")
        repo.git.clean("-fd")

        self.log(
            {
                "action": "local_refresh_done",
                "repo_path": str(repo_path),
                "remote": remote.name,
                "branch": target_branch,
            }
        )

        return target_branch

    def _clone_repo(self, clone_url: str, repo_path: Path, branch: str | None) -> str | None:
        self.log(
            {
                "action": "clone_start",
                "clone_url": clone_url,
                "repo_path": str(repo_path),
                "branch_requested": branch,
            }
        )

        repo = Repo.clone_from(clone_url, str(repo_path))
        active_branch = self._checkout_branch_strict(repo, branch)

        self.log(
            {
                "action": "clone_done",
                "repo_path": str(repo_path),
                "branch_active": active_branch,
            }
        )

        return active_branch

    def _list_candidate_files(self, repo_path: Path, root_folder: str) -> list[str]:
        root = repo_path / root_folder if root_folder else repo_path
        if not root.exists():
            return []

        files = []
        for path in root.rglob("*"):
            if path.is_file():
                files.append(self._relative_path(path, repo_path))
        return sorted(files)

    @asynccontextmanager
    async def temp_clone_dir(self):
        temp_dir = None
        try:
            temp_dir = tempfile.mkdtemp(prefix="langflow_clone_")
            yield temp_dir
        finally:
            if temp_dir:
                shutil.rmtree(temp_dir, ignore_errors=True)

    def update_build_config(self, build_config: dict, field_value: str, field_name: str | None = None) -> dict:
        if field_name == "repo_source":
            if field_value == "Local":
                build_config["repo_path"]["required"] = True
                build_config["clone_url"]["required"] = False
            elif field_value == "Remote":
                build_config["clone_url"]["required"] = True
                build_config["repo_path"]["required"] = False
        return build_config

    async def _load_from_repo(self, repo_path: Path, root_folder: str, branch: str | None) -> list[Data]:
        root_path = repo_path / root_folder if root_folder else repo_path
        if root_folder and not root_path.exists():
            raise ValueError(f"Root folder not found in repository: {root_folder}")

        discovered_files = self._list_candidate_files(repo_path, root_folder)

        self.log(
            {
                "action": "scan_repo",
                "repo_path": str(repo_path),
                "root_folder": root_folder,
                "branch": branch,
                "discovered_files_count": len(discovered_files),
                "discovered_files_preview": discovered_files[:20],
            }
        )

        gitloader = GitLoader(
            repo_path=str(repo_path),
            clone_url=None,
            branch=branch,
            file_filter=lambda p: self._skill_file_filter(p, repo_path, root_folder),
        )

        docs = [self._doc_to_data(doc, repo_path) async for doc in gitloader.alazy_load()]

        self.log(
            {
                "action": "load_done",
                "repo_path": str(repo_path),
                "loaded_docs": len(docs),
                "loaded_paths": [doc.data.get("path") for doc in docs[:20]],
            }
        )

        self.status = {
            "loaded_docs": len(docs),
            "loaded_paths_preview": [doc.data.get("path") for doc in docs[:20]],
            "branch": branch,
            "root_folder": root_folder,
        }

        return docs

    async def load_documents(self) -> list[Data]:
        repo_source = (getattr(self, "repo_source", None) or "Remote").strip()
        root_folder = self._normalize_root_folder(getattr(self, "root_folder", None) or "skills")
        branch = (getattr(self, "branch", None) or "").strip() or None
        repo_path_value = (getattr(self, "repo_path", None) or "").strip()
        clone_url = (getattr(self, "clone_url", None) or "").strip()
        force_refresh = bool(getattr(self, "force_refresh", True))

        self.log(
            {
                "action": "load_start",
                "repo_source": repo_source,
                "repo_path_provided": bool(repo_path_value),
                "clone_url_provided": bool(clone_url),
                "branch_requested": branch,
                "root_folder": root_folder,
                "force_refresh": force_refresh,
            }
        )

        if repo_source == "Local":
            if not repo_path_value:
                raise ValueError("Local Repository Path is required when Repository Source is 'Local'.")

            repo_path = Path(repo_path_value)
            if not repo_path.exists():
                raise ValueError(f"Local repository path does not exist: {repo_path}")
            if not (repo_path / ".git").exists():
                raise ValueError(f"Local path is not a git repository: {repo_path}")

            active_branch = branch
            if force_refresh:
                active_branch = self._refresh_local_repo(repo_path, branch)
            else:
                repo = Repo(str(repo_path))
                active_branch = self._checkout_branch_strict(repo, branch)

            return await self._load_from_repo(repo_path, root_folder, active_branch)

        if not clone_url:
            raise ValueError(
                "Clone URL is empty. In Langflow, keep the field visible and fill it explicitly when Repository Source is 'Remote'."
            )

        async with self.temp_clone_dir() as temp_dir:
            repo_path = Path(temp_dir)
            active_branch = self._clone_repo(clone_url, repo_path, branch)
            return await self._load_from_repo(repo_path, root_folder, active_branch)

from __future__ import annotations

import json
import re
import unicodedata
from pathlib import PurePosixPath
from typing import Any

import yaml

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, IntInput, MessageTextInput, Output
from lfx.schema.data import Data


class RillSkillsLoader(Component):
    display_name = "Rill Skills Loader"
    description = "Loads Rill skill YAML files from Git JSON and exposes skill retrieval as an Agent tool."
    documentation = "https://docs.langflow.org/components-custom-components"
    icon = "FileSearch"
    name = "RillSkillsLoader"

    inputs = [
        DataInput(
            name="git_json",
            display_name="Git JSON",
            info="JSON/Data output from the Git component. Only skills/*.yaml and skills/*.yml files are loaded.",
            required=True,
            tool_mode=False,
        ),
        MessageTextInput(
            name="query",
            display_name="Query",
            info="User question used to retrieve the most relevant Rill skills.",
            required=True,
            tool_mode=True,
        ),
        IntInput(
            name="top_k",
            display_name="Top K",
            info="Maximum number of skills to return.",
            value=5,
            required=False,
            tool_mode=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Retrieve Rill Skills",
            name="retrieve_rill_skills",
            method="retrieve_rill_skills",
        ),
        Output(
            display_name="Get Rill Skill",
            name="get_rill_skill",
            method="get_rill_skill",
        ),
    ]

    # -------------------------
    # Helpers
    # -------------------------

    def _unwrap(self, value: Any) -> Any:
        if isinstance(value, Data):
            return value.data

        if hasattr(value, "data"):
            return value.data

        if hasattr(value, "text"):
            text = value.text
            try:
                return json.loads(text)
            except Exception:
                return text

        if isinstance(value, str):
            try:
                return json.loads(value)
            except Exception:
                return value

        return value

    def _normalize_text(self, value: str) -> str:
        value = str(value or "").lower()
        value = unicodedata.normalize("NFKD", value)
        value = "".join(c for c in value if not unicodedata.combining(c))
        return value

    def _tokens(self, value: str) -> set[str]:
        value = self._normalize_text(value)
        return set(re.findall(r"[a-z0-9_]+", value))

    def _normalize_path(self, path: str) -> str:
        path = str(path or "").replace("\\", "/").strip()
        path = path.replace("file://", "")

        if "skills/" in path:
            path = path[path.index("skills/"):]

        return path.strip("/")

    def _is_skill_path(self, path: str) -> bool:
        path = self._normalize_path(path)
        return path.startswith("skills/") and path.endswith((".yaml", ".yml"))

    def _safe_list(self, value: Any) -> list[str]:
        if isinstance(value, list):
            return [str(x) for x in value if x is not None]
        if value is None:
            return []
        return [str(value)]

    # -------------------------
    # Git payload extraction
    # -------------------------

    def _extract_git_files(self, payload: Any) -> list[dict[str, str]]:
        payload = self._unwrap(payload)
        files: list[dict[str, str]] = []

        def get_path(obj: dict[str, Any]) -> str:
            metadata = obj.get("metadata") or {}

            candidates = [
                obj.get("path"),
                obj.get("file_path"),
                obj.get("filename"),
                obj.get("name"),
                obj.get("source"),
                metadata.get("path"),
                metadata.get("file_path"),
                metadata.get("filename"),
                metadata.get("name"),
                metadata.get("source"),
            ]

            for candidate in candidates:
                if isinstance(candidate, str) and candidate.strip():
                    return self._normalize_path(candidate)

            return ""

        def get_content(obj: dict[str, Any]) -> str:
            candidates = [
                obj.get("content"),
                obj.get("page_content"),
                obj.get("text"),
                obj.get("value"),
            ]

            for candidate in candidates:
                if isinstance(candidate, str) and candidate.strip():
                    return candidate

            return ""

        def walk(node: Any):
            node = self._unwrap(node)

            if isinstance(node, list):
                for item in node:
                    walk(item)
                return

            if isinstance(node, dict):
                path = get_path(node)
                content = get_content(node)

                if path and content:
                    files.append({"path": path, "content": content})

                for key, value in node.items():
                    if isinstance(key, str) and isinstance(value, str):
                        normalized_key = self._normalize_path(key)
                        if self._is_skill_path(normalized_key):
                            files.append(
                                {
                                    "path": normalized_key,
                                    "content": value,
                                }
                            )

                for key in ("documents", "files", "data", "results", "items"):
                    if key in node:
                        walk(node[key])

        walk(payload)

        dedup: dict[str, dict[str, str]] = {}
        for item in files:
            path = self._normalize_path(item.get("path", ""))
            content = item.get("content", "")
            if path and content:
                dedup[path] = {"path": path, "content": content}

        return list(dedup.values())

    # -------------------------
    # Catalog
    # -------------------------

    def _load_catalog(self) -> dict[str, Any]:
        git_files = self._extract_git_files(self.git_json)

        skills: dict[str, dict[str, Any]] = {}
        skill_index: dict[str, Any] = {}
        loaded_paths: list[str] = []
        ignored_paths: list[str] = []
        parse_errors: list[dict[str, str]] = []

        for item in git_files:
            path = self._normalize_path(item.get("path", ""))
            content = item.get("content", "")

            if not self._is_skill_path(path):
                ignored_paths.append(path)
                continue

            try:
                parsed = yaml.safe_load(content) or {}
            except Exception as exc:
                parse_errors.append({"path": path, "error": str(exc)})
                continue

            if not isinstance(parsed, dict):
                parse_errors.append({"path": path, "error": "YAML root must be a mapping/object"})
                continue

            filename = PurePosixPath(path).name

            if filename == "skill_index.yaml":
                skill_index = parsed
                loaded_paths.append(path)
                continue

            skill_id = parsed.get("skill_id") or filename.replace(".yaml", "").replace(".yml", "")
            parsed["skill_id"] = skill_id
            parsed["_source_path"] = path

            if "planner_contract" not in parsed or not isinstance(parsed.get("planner_contract"), dict):
                parsed["planner_contract"] = {}

            skills[skill_id] = parsed
            loaded_paths.append(path)

        if not skills:
            raise ValueError(
                "No skills loaded. Check Git branch, Git output, and make sure files exist under skills/*.yaml."
            )

        self.log(
            {
                "action": "load_catalog",
                "loaded_skills": len(skills),
                "loaded_paths": loaded_paths[:20],
                "ignored_paths_count": len(ignored_paths),
                "parse_errors": parse_errors,
            }
        )

        return {
            "skills": skills,
            "skill_index": skill_index,
            "loaded_paths": loaded_paths,
            "ignored_paths": ignored_paths,
            "parse_errors": parse_errors,
        }

    def _score_skill(self, query: str, skill: dict[str, Any]) -> float:
        q = self._normalize_text(query)
        query_tokens = self._tokens(q)
        planner_contract = skill.get("planner_contract", {}) or {}

        corpus_parts = [
            skill.get("skill_id", ""),
            skill.get("name", ""),
            skill.get("description", ""),
            skill.get("skill_type", ""),
            " ".join(self._safe_list(skill.get("use_when", []))),
            " ".join(self._safe_list(skill.get("avoid_when", []))),
            " ".join(self._safe_list(skill.get("aliases", []))),
            " ".join(self._safe_list(planner_contract.get("accepted_metrics", []))),
            " ".join(self._safe_list(planner_contract.get("default_metrics", []))),
            " ".join(self._safe_list(planner_contract.get("required_filters", []))),
            " ".join(self._safe_list(planner_contract.get("optional_filters", []))),
            " ".join(self._safe_list(planner_contract.get("expected_output_sections", []))),
            str(planner_contract.get("intent", "")),
            str(planner_contract.get("report_type", "")),
            str(planner_contract.get("task_type", "")),
            str(planner_contract.get("default_metric", "")),
        ]

        corpus = self._normalize_text(" ".join(str(x) for x in corpus_parts if x))
        corpus_tokens = self._tokens(corpus)

        score = 0.0

        for token in query_tokens:
            if token in corpus_tokens:
                score += 1.0
            if token in self._normalize_text(skill.get("skill_id", "")):
                score += 2.0
            if token in self._normalize_text(skill.get("name", "")):
                score += 1.5

        skill_id = skill.get("skill_id", "")
        report_type = str(planner_contract.get("report_type", ""))

        if any(x in q for x in ["detail financier", "details financier", "détails financier", "financial detail", "profil financier"]):
            if "brand_financial_detail" in skill_id or report_type == "brand_detail":
                score += 12.0

        if any(x in q for x in ["top brand", "top brands", "top marques", "classement marques"]):
            if "top_brands" in skill_id or report_type == "top_brands":
                score += 10.0

        if any(x in q for x in ["top country", "top countries", "top pays", "classement pays"]):
            if "top_countries" in skill_id or report_type == "top_countries":
                score += 10.0

        if any(x in q for x in ["top media", "top medias", "canaux", "media ranking"]):
            if "top_media" in skill_id or report_type == "top_media":
                score += 10.0

        if any(x in q for x in ["trend", "tendance", "mensuel", "monthly"]):
            if "monthly_trend" in skill_id or report_type == "monthly_trend":
                score += 10.0

        if any(x in q for x in ["dashboard", "overview", "synthese", "synthèse", "global"]):
            if "dashboard" in skill_id or report_type == "dashboard":
                score += 6.0

        return score

    def _serialize_skill(self, score: float, skill_id: str, skill: dict[str, Any]) -> dict[str, Any]:
        planner_contract = skill.get("planner_contract", {}) or {}

        return {
            "score": score,
            "skill_id": skill_id,
            "name": skill.get("name"),
            "description": skill.get("description"),
            "skill_type": skill.get("skill_type"),
            "use_when": self._safe_list(skill.get("use_when", [])),
            "avoid_when": self._safe_list(skill.get("avoid_when", [])),
            "endpoint": skill.get("endpoint", {}),
            "parameters": skill.get("parameters", {}),
            "response_contract": skill.get("response_contract", {}),
            "planner_hints": skill.get("planner_hints", {}),
            "planner_contract": planner_contract,
            "task_type": planner_contract.get("task_type", ""),
            "intent": planner_contract.get("intent", ""),
            "report_type": planner_contract.get("report_type", ""),
            "default_metric": planner_contract.get("default_metric", ""),
            "default_metrics": self._safe_list(planner_contract.get("default_metrics", [])),
            "accepted_metrics": self._safe_list(planner_contract.get("accepted_metrics", [])),
            "required_filters": self._safe_list(planner_contract.get("required_filters", [])),
            "optional_filters": self._safe_list(planner_contract.get("optional_filters", [])),
            "group_by": self._safe_list(planner_contract.get("group_by", [])),
            "limit": planner_contract.get("limit", 15),
            "query_budget_params": planner_contract.get("query_budget_params", {}),
            "expected_output_sections": self._safe_list(planner_contract.get("expected_output_sections", [])),
            "frontend_expectation": planner_contract.get("frontend_expectation", {}),
            "compiler_hints": planner_contract.get("compiler_hints", {}),
            "metric_column_mapping": skill.get("metric_column_mapping", {}),
            "filter_contract": skill.get("filter_contract", {}),
            "output_contract": skill.get("output_contract", {}),
            "guardrails": self._safe_list(skill.get("guardrails", [])),
            "source_path": skill.get("_source_path"),
        }

    # -------------------------
    # Tool actions
    # -------------------------

    def retrieve_rill_skills(self) -> Data:
        catalog = self._load_catalog()
        skills = catalog["skills"]

        query = self.query or ""
        top_k = int(self.top_k or 5)
        top_k = max(1, min(top_k, 10))

        ranked: list[tuple[float, str, dict[str, Any]]] = []
        for skill_id, skill in skills.items():
            score = self._score_skill(query, skill)
            ranked.append((score, skill_id, skill))

        ranked.sort(key=lambda x: x[0], reverse=True)
        selected = ranked[:top_k]

        result = {
            "status": "ok",
            "query": query,
            "top_k": top_k,
            "loaded_skills": len(skills),
            "loaded_paths": catalog["loaded_paths"],
            "ignored_paths": catalog["ignored_paths"],
            "parse_errors": catalog["parse_errors"],
            "skills": [
                self._serialize_skill(score, skill_id, skill)
                for score, skill_id, skill in selected
            ],
        }

        self.status = {
            "loaded_skills": len(skills),
            "top_skill": selected[0][1] if selected else None,
            "parse_errors": catalog["parse_errors"],
        }

        self.log(
            {
                "action": "retrieve_rill_skills",
                "query": query,
                "top_skill": selected[0][1] if selected else None,
                "top_k": top_k,
            }
        )

        return Data(data=result)

    def get_rill_skill(self) -> Data:
        catalog = self._load_catalog()
        skills = catalog["skills"]

        query = (self.query or "").strip()
        if not query:
            raise ValueError("Query is required. Pass a skill_id in the query field for get_rill_skill.")

        if query in skills:
            skill = skills[query]
            return Data(
                data={
                    "status": "ok",
                    "skill": self._serialize_skill(1.0, query, skill),
                }
            )

        normalized_query = self._normalize_text(query)
        for skill_id, skill in skills.items():
            if normalized_query == self._normalize_text(skill_id) or normalized_query == self._normalize_text(skill.get("name", "")):
                return Data(
                    data={
                        "status": "ok",
                        "skill": self._serialize_skill(1.0, skill_id, skill),
                    }
                )

        raise ValueError(f"Skill not found: {query}")

from __future__ import annotations

import json
from pathlib import PurePosixPath
from typing import Any

import yaml

from lfx.custom.custom_component.component import Component
from lfx.inputs.inputs import HandleInput
from lfx.io import Output
from lfx.schema.data import Data


class BudgetIntentCompiler(Component):
    display_name = "Budget Intent Compiler"
    description = (
        "Completes a BudgetPlannerAgent intent using deterministic planner_contract "
        "from the selected Rill skill YAML."
    )
    documentation = "https://docs.langflow.org/components-custom-components"
    icon = "Braces"
    name = "BudgetIntentCompiler"

    inputs = [
        HandleInput(
            name="input_value",
            display_name="Planner Intent",
            info="Structured response from BudgetPlannerAgent.",
            input_types=["Data", "JSON", "Message"],
            required=True,
        ),
        HandleInput(
            name="git_json",
            display_name="Git JSON",
            info="JSON/Data output from the Git component containing skills/*.yaml.",
            input_types=["Data", "JSON", "Message"],
            required=True,
        ),
    ]

    outputs = [
        Output(
            display_name="Compiled Budget Intent",
            name="compiled_intent",
            method="compile_intent",
        )
    ]

    FALLBACK_CONTRACTS: dict[str, dict[str, Any]] = {
        "budget_top_brands": {
            "task_type": "query",
            "report_type": "top_brands",
            "default_metric": "media_net",
            "default_metrics": ["media_net"],
            "group_by": ["brand"],
            "limit": 15,
        },
        "budget_top_countries": {
            "task_type": "query",
            "report_type": "top_countries",
            "default_metric": "media_net",
            "default_metrics": ["media_net"],
            "group_by": ["country"],
            "limit": 15,
        },
        "budget_top_media": {
            "task_type": "query",
            "report_type": "top_media",
            "default_metric": "media_net",
            "default_metrics": ["media_net"],
            "group_by": ["media"],
            "limit": 15,
        },
        "budget_monthly_trend": {
            "task_type": "query",
            "report_type": "monthly_trend",
            "default_metric": "media_net",
            "default_metrics": ["media_net"],
            "group_by": ["month"],
            "limit": 15,
        },
        "budget_dashboard_data_filtered": {
            "task_type": "query",
            "report_type": "dashboard",
            "default_metric": "media_net",
            "default_metrics": ["media_net"],
            "group_by": [],
            "limit": 15,
        },
        "budget_brand_financial_detail": {
            "task_type": "query",
            "report_type": "brand_detail",
            "default_metric": "media_net",
            "default_metrics": [
                "media_net",
                "gross_investment",
                "committed",
                "proposal_amount",
                "purchase_order_amount",
                "technical_costs",
                "media_agency_fees",
                "media_taxes",
                "rate_card",
            ],
            "required_filters": ["brand"],
            "optional_filters": [
                "country",
                "media",
                "status",
                "workflow_process",
            ],
            "group_by": [],
            "limit": 15,
            "compiler_hints": {
                "force_default_metrics": True,
                "never_reduce_to_single_media_net_only": True,
            },
        },
    }

    def compile_intent(self) -> Data:
        intent = self._extract_payload(self.input_value)
        skills = self._load_skills(self.git_json)

        compiled = self._compile(intent=intent, skills=skills)

        self.status = {
            "status": compiled.get("status"),
            "selected_skill": compiled.get("selected_skill"),
            "report_type": compiled.get("report_type"),
            "metric": compiled.get("metric"),
            "metrics": compiled.get("metrics"),
            "filters": compiled.get("filters"),
        }

        return Data(data=compiled)

    def _compile(
        self,
        *,
        intent: dict[str, Any],
        skills: dict[str, dict[str, Any]],
    ) -> dict[str, Any]:
        if not isinstance(intent, dict):
            intent = {}

        if isinstance(intent.get("data"), dict) and intent["data"].get("selected_skill"):
            intent = intent["data"]

        compiled = dict(intent)
        compiled.pop("default_value", None)

        warnings = list(compiled.get("warnings") or [])
        errors = list(compiled.get("errors") or [])

        skill_id = self._clean_str(compiled.get("selected_skill"))
        skill = skills.get(skill_id) or {}

        planner_contract = (
            skill.get("planner_contract")
            or self.FALLBACK_CONTRACTS.get(skill_id)
            or {}
        )

        compiler_hints = planner_contract.get("compiler_hints") or {}

        compiled["version"] = self._clean_str(compiled.get("version")) or "1.0"
        compiled["component"] = "BudgetIntentCompiler"
        compiled["status"] = self._clean_str(compiled.get("status")) or "ok"
        compiled["selected_skill"] = skill_id
        compiled["warnings"] = warnings
        compiled["errors"] = errors

        compiled["filters"] = self._ensure_list(compiled.get("filters"))
        compiled["group_by"] = self._ensure_list(compiled.get("group_by"))
        compiled["metrics"] = self._ensure_list(compiled.get("metrics"))

        compiled["compare"] = self._ensure_dict(compiled.get("compare"))
        compiled["pivot"] = self._ensure_dict(compiled.get("pivot"))
        compiled["clarification"] = self._ensure_dict(compiled.get("clarification"))

        compiled["is_follow_up"] = bool(compiled.get("is_follow_up", False))
        compiled["keep_missing_context"] = bool(compiled.get("keep_missing_context", False))
        compiled["confidence"] = self._safe_float(compiled.get("confidence"), default=0.0)

        if planner_contract:
            compiled["task_type"] = (
                self._clean_str(compiled.get("task_type"))
                or self._clean_str(planner_contract.get("task_type"))
                or "query"
            )

            compiled["report_type"] = (
                self._clean_str(compiled.get("report_type"))
                or self._clean_str(planner_contract.get("report_type"))
            )

            current_metric = self._clean_str(compiled.get("metric"))
            default_metric = self._clean_str(planner_contract.get("default_metric")) or "media_net"

            compiled["metric"] = current_metric or default_metric

            default_metrics = self._ensure_list(planner_contract.get("default_metrics"))
            force_default_metrics = bool(
                compiler_hints.get("force_default_metrics")
                or skill_id == "budget_brand_financial_detail"
            )

            if force_default_metrics and default_metrics:
                compiled["metrics"] = default_metrics
            elif not compiled["metrics"]:
                if default_metrics:
                    if len(default_metrics) == 1:
                        compiled["metrics"] = [compiled["metric"]]
                    else:
                        compiled["metrics"] = default_metrics
                elif compiled["metric"]:
                    compiled["metrics"] = [compiled["metric"]]

            if not compiled["group_by"]:
                compiled["group_by"] = self._ensure_list(planner_contract.get("group_by"))

            compiled["limit"] = self._safe_int(
                compiled.get("limit"),
                default=self._safe_int(planner_contract.get("limit"), default=15),
            )

            compiled = self._validate_required_filters(
                compiled=compiled,
                required_filters=self._ensure_list(planner_contract.get("required_filters")),
            )
        else:
            compiled["task_type"] = self._clean_str(compiled.get("task_type")) or "query"
            compiled["report_type"] = self._clean_str(compiled.get("report_type"))
            compiled["metric"] = self._clean_str(compiled.get("metric")) or "media_net"

            if not compiled["metrics"]:
                compiled["metrics"] = [compiled["metric"]]

            compiled["limit"] = self._safe_int(compiled.get("limit"), default=15)

            warnings.append(
                f"No planner_contract found for selected_skill='{skill_id}'. Used safe fallback defaults."
            )

        for key in ["selected_skill", "task_type", "report_type", "metric"]:
            compiled[key] = self._clean_str(compiled.get(key))

        if compiled.get("metric") and not compiled.get("metrics"):
            compiled["metrics"] = [compiled["metric"]]

        compiled["filters"] = self._normalize_filters(compiled["filters"])
        compiled["group_by"] = [self._clean_str(x) for x in compiled["group_by"] if self._clean_str(x)]
        compiled["metrics"] = [self._clean_str(x) for x in compiled["metrics"] if self._clean_str(x)]

        compiled["warnings"] = [str(x) for x in warnings if str(x).strip()]
        compiled["errors"] = errors

        return compiled

    def _validate_required_filters(
        self,
        *,
        compiled: dict[str, Any],
        required_filters: list[Any],
    ) -> dict[str, Any]:
        required = [self._clean_str(x) for x in required_filters if self._clean_str(x)]

        if not required:
            return compiled

        present = {
            self._clean_str(item.get("dimension"))
            for item in compiled.get("filters", [])
            if isinstance(item, dict)
        }

        missing = [dimension for dimension in required if dimension not in present]

        if missing:
            compiled["status"] = "clarification_needed"
            compiled["clarification"] = {
                "missing_required_filters": missing,
                "message": f"Missing required filter(s): {', '.join(missing)}",
            }

            compiled.setdefault("warnings", [])
            compiled["warnings"].append(
                f"Selected skill requires filter(s): {', '.join(missing)}."
            )

        return compiled

    def _load_skills(self, payload: Any) -> dict[str, dict[str, Any]]:
        git_files = self._extract_git_files(payload)
        skills: dict[str, dict[str, Any]] = {}

        for item in git_files:
            path = self._normalize_path(item.get("path", ""))
            content = item.get("content", "")

            if not self._is_skill_path(path):
                continue

            filename = PurePosixPath(path).name

            if filename == "skill_index.yaml":
                continue

            try:
                parsed = yaml.safe_load(content) or {}
            except Exception:
                continue

            if not isinstance(parsed, dict):
                continue

            skill_id = (
                self._clean_str(parsed.get("skill_id"))
                or filename.replace(".yaml", "").replace(".yml", "")
            )

            parsed["skill_id"] = skill_id
            parsed["_source_path"] = path

            skills[skill_id] = parsed

        return skills

    def _extract_git_files(self, payload: Any) -> list[dict[str, str]]:
        payload = self._unwrap(payload)
        files: list[dict[str, str]] = []

        def get_path(obj: dict[str, Any]) -> str:
            metadata = obj.get("metadata") or {}
            data = obj.get("data") if isinstance(obj.get("data"), dict) else {}

            candidates = [
                obj.get("path"),
                obj.get("file_path"),
                obj.get("filename"),
                obj.get("name"),
                obj.get("source"),
                metadata.get("path"),
                metadata.get("file_path"),
                metadata.get("filename"),
                metadata.get("name"),
                metadata.get("source"),
                data.get("path"),
                data.get("file_path"),
                data.get("filename"),
                data.get("name"),
                data.get("source"),
            ]

            for candidate in candidates:
                if isinstance(candidate, str) and candidate.strip():
                    return self._normalize_path(candidate)

            return ""

        def get_content(obj: dict[str, Any]) -> str:
            data = obj.get("data") if isinstance(obj.get("data"), dict) else {}

            candidates = [
                obj.get("content"),
                obj.get("page_content"),
                obj.get("text"),
                obj.get("value"),
                obj.get("raw_content"),
                obj.get("body"),
                data.get("content"),
                data.get("page_content"),
                data.get("text"),
                data.get("value"),
                data.get("raw_content"),
                data.get("body"),
            ]

            for candidate in candidates:
                if isinstance(candidate, str) and candidate.strip():
                    return candidate

            return ""

        def walk(node: Any):
            node = self._unwrap(node)

            if isinstance(node, list):
                for item in node:
                    walk(item)
                return

            if isinstance(node, dict):
                path = get_path(node)
                content = get_content(node)

                if path and content:
                    files.append({"path": path, "content": content})

                for key, value in node.items():
                    if isinstance(key, str) and isinstance(value, str):
                        normalized_key = self._normalize_path(key)
                        if self._is_skill_path(normalized_key):
                            files.append(
                                {
                                    "path": normalized_key,
                                    "content": value,
                                }
                            )

                for key in ("documents", "files", "data", "results", "items"):
                    if key in node:
                        walk(node[key])

        walk(payload)
        return files

    def _extract_payload(self, value: Any) -> dict[str, Any]:
        value = self._unwrap(value)

        if isinstance(value, dict):
            if isinstance(value.get("data"), dict) and value["data"].get("selected_skill"):
                return value["data"]
            return value

        if isinstance(value, str):
            return self._loads_json(value)

        return {}

    def _unwrap(self, value: Any) -> Any:
        if isinstance(value, Data):
            return value.data

        if hasattr(value, "data"):
            return value.data

        if hasattr(value, "text"):
            text = value.text
            try:
                return json.loads(text)
            except Exception:
                return text

        if hasattr(value, "content"):
            content = value.content
            try:
                return json.loads(content)
            except Exception:
                return content

        if isinstance(value, str):
            try:
                return json.loads(value)
            except Exception:
                return value

        return value

    def _loads_json(self, text: str) -> dict[str, Any]:
        text = (text or "").strip()

        if not text:
            return {}

        try:
            payload = json.loads(text)
            return payload if isinstance(payload, dict) else {}
        except Exception:
            pass

        start = text.find("{")
        end = text.rfind("}")

        if start >= 0 and end > start:
            try:
                payload = json.loads(text[start : end + 1])
                return payload if isinstance(payload, dict) else {}
            except Exception:
                return {}

        return {}

    def _normalize_path(self, path: str) -> str:
        path = str(path or "").replace("\\", "/").strip()
        path = path.replace("file://", "")

        if "skills/" in path:
            path = path[path.index("skills/"):]

        return path.strip("/")

    def _is_skill_path(self, path: str) -> bool:
        path = self._normalize_path(path)
        return path.startswith("skills/") and path.endswith((".yaml", ".yml"))

    def _clean_str(self, value: Any) -> str:
        if value is None:
            return ""

        text = str(value).strip()

        if text.casefold() in {"null", "none", "undefined"}:
            return ""

        return text

    def _ensure_list(self, value: Any) -> list[Any]:
        if value is None:
            return []

        if isinstance(value, list):
            return value

        if isinstance(value, tuple):
            return list(value)

        if value in ("", "null", "None"):
            return []

        return [value]

    def _ensure_dict(self, value: Any) -> dict[str, Any]:
        if isinstance(value, dict):
            return value

        return {}

    def _safe_int(self, value: Any, default: int = 15) -> int:
        try:
            number = int(value)
        except Exception:
            return default

        return number if number > 0 else default

    def _safe_float(self, value: Any, default: float = 0.0) -> float:
        try:
            return float(value)
        except Exception:
            return default

    def _normalize_filters(self, filters: list[Any]) -> list[dict[str, str]]:
        output: list[dict[str, str]] = []

        for item in filters:
            if not isinstance(item, dict):
                continue

            dimension = self._clean_str(item.get("dimension"))
            source_value = self._clean_str(item.get("source_value"))

            if not dimension or not source_value:
                continue

            output.append(
                {
                    "dimension": dimension,
                    "source_value": source_value,
                }
            )

        return output
